import React, { useState, useEffect } from "react";
import dayjs from "dayjs";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

const commonGrid = {
  grid: {
    display: false,
    drawBorder: false,
  },
  ticks: {
    font: { size: 11 },
  },
};

function Dashboard() {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768);
    };
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const barThickness = isMobile ? 20 : 50;
  const maxBarThickness = isMobile ? 20 : 55;

  /* ================= STATIC ADMIN DATA ================= */

  const adminProfile = {
    name: "Admin User",
    lastUpdated: new Date(),
  };

  const summaryCards = {
    totalUsers: 1250,
    totalLeads: 842,
    totalRevenue: 2450000,
    totalSupportTickets: 128,
  };

  const supportData = {
    pending: 24,
    resolved: 104,
  };

  return (
    <div className="container py-3">
      {/* Header */}
      <h4 className="fw-bold fs-3">
        Welcome, {adminProfile.name}
      </h4>
      <small>
        Last Updated:{" "}
        {dayjs(adminProfile.lastUpdated).format("DD MMM YYYY, hh:mm A")}
      </small>

      {/* Summary Cards */}
      <div className="row g-3 mt-3">
        <div className="col-md-3 col-6">
          <div className="p-3 border rounded bg-body">
            <small>Total Users</small>
            <h5>{summaryCards.totalUsers}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 border rounded bg-body">
            <small>Total Leads</small>
            <h5>{summaryCards.totalLeads}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 border rounded bg-body">
            <small>Total Revenue</small>
            <h5>
              ₹{summaryCards.totalRevenue.toLocaleString("en-IN")}
            </h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 border rounded bg-body">
            <small>Support Tickets</small>
            <h5>{summaryCards.totalSupportTickets}</h5>
          </div>
        </div>
      </div>

      {/* Support Overview */}
      <div className="row mt-4">
        <div className="col-md-6 col-12">
          <div className="p-3 border-start border-5 border-warning rounded bg-body">
            <h5>Support Overview</h5>
            <p className="mb-1">Pending: {supportData.pending}</p>
            <p className="mb-0">Resolved: {supportData.resolved}</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
